var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 후. 로터스, 아마니 벨리. \\n관리국 부설건물, 접객실 복도.","JPN":"1週間後。ロータス、アマニーバレー。\\n管理局の付属施設、接客室の廊下。","ENG":"[[","TWN":"一週前。洛德斯，和平谷。\\n管理局附屬大樓，接待室走廊。","SCN":"一周前。洛德斯，和平谷。\\n管理局附属大楼，接待室走廊。","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 연락이 안 되는군.","JPN":"やはり連絡が取れないな。","ENG":"She's not answering as expected.","TWN":"果然聯絡不上。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"오래 기다리게 해서 죄송합니다.","JPN":"長らくお待たせして申し訳ございません。","ENG":"I apologize for keeping you waiting for so long.","TWN":"抱歉，讓你久等了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"최고관리자님의 방문 소식을 시니어님에게 전달드렸습니다만, 만남을 거부했습니다.","JPN":"最高管理者様のご訪問をシニアにお伝えしたのですが、面会を拒否しておりました。","ENG":"I notified our Senior of the Supreme Administrator's visit, but she has refused to meet with you.","TWN":"我已經將最高管理者來訪的消息傳達給了前輩，但她仍然拒絕會面。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"굳이 덧붙이자면. <color=#ffd34c>세상이 멸망해도 만나지 않겠다는 점</color>을 최대한 강조하라더군요.","JPN":"強いて付け加えると。<color=#ffd34c>世界が滅亡しても顔を合わせることはない</color>と最大限強調するようにおっしゃっていました。","ENG":"If I may add. She wanted me to emphasize it by saying that <color=#ffd34c>she wouldn't meet you even if the world was ending</color>.","TWN":"硬要補充的話。她希望我強調<color=#ffd34c>即使世界毀滅也不會見面的</color>這一點。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 말이 농담이 아니라면 마음에 상처를 받겠군.","JPN":"その言葉が冗談でないなら、傷つくな。","ENG":"It would be very hurtful if she wasn't joking.","TWN":"如果你不是在開玩笑，那我可要傷心了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"대신 사과드리겠습니다.","JPN":"代わりにお詫び申し上げます。","ENG":"I apologize on her behalf.","TWN":"我替她向你道歉。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"저희 시니어님은 별 대수롭지 않은 이유로 본인의 책임을 자주 망각하는 분입니다.","JPN":"シニア様はささいなことでご自身の役目を頻繁に忘れる方です。","ENG":"Ms. Isolde is someone who often forgets her responsibilities for insignificant reasons.","TWN":"我們前輩經常因為一些無關緊要的理由而忘記自己的職責。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"사고의 수준이 사탕을 빼앗으면 우는 어린아이나 다름없죠.","JPN":"思考のレベルが、飴を奪われると泣く子どもと同じなのです。","ENG":"Her mentality is no different from a child who cries after someone takes her candy away.","TWN":"她的思考模式有時與被搶了糖果就哭的孩童無異。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠… 부하직원이 그런 표현을 써도 괜찮은 건가? 저 방 안에서 다 듣고 있을 텐데.","JPN":"コホン……部下の職員がそんな表現を使ってもいいのかね？　あの部屋の中ですべて聞いているはずだが。","ENG":"Ahem... Are you sure you are allowed to talk about her like that? I bet she's listening to this conversation from her room right now.","TWN":"咳咳……你作為下屬用那種表達方式真的沒問題嗎？她在那個房間裡應該聽得一清二楚吧。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"저의 징계나 해고는 걱정거리 축에도 끼지 않습니다.","JPN":"私の懲戒や解雇についてはご心配には及びません。","ENG":"Disciplinary actions or dismissals are not even on the list of concerns.","TWN":"對於我的懲罰或者解雇根本不值得擔心。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"공사 구분도 할 줄 모르는 시니어님의 통찰력이 가져오게 될 로터스의 불운한 미래가 걱정될 따름이죠.","JPN":"公私の区別もつかないシニア様の洞察力がもたらす、ロータスの不運に満ちた未来が心配なだけです。","ENG":"I am just concerned about the unfortunate future that Lotus is facing due to a Senior who cannot keep her personal and professional lives separate.","TWN":"我只會擔心不懂得公私分明的前輩會給洛德斯帶來不幸的未來。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"방금 그 소린 뭐였지?","JPN":"今の音は何だ？","ENG":"What was that sound just now?","TWN":"剛、剛才那個聲音是什麼？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"시니어님은 흥분하면 주먹으로 벽을 때리는 버릇이 있습니다.","JPN":"シニア様は興奮すると拳で壁を叩く癖があります。","ENG":"Ms. Isolde has a habit of punching the wall with her fist when she is frustrated.","TWN":"前輩一激動就有用拳頭錘牆的習慣。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"지난 번처럼 골절된 건 아닐지 걱정이군요.","JPN":"この前のように骨折していないか、心配ですね。","ENG":"I just hope she hasn't broken her fist like last time.","TWN":"希望這次不要像上次那樣骨折了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다행이군. 듣고 있다는 건 적어도 내 방문에 관심은 있다는 뜻이니 말이야.","JPN":"よかった。聞いているということは、少なくとも私の訪問に興味がないわけではないようだから。","ENG":"That's good news. Her eavesdropping means that she's interested in my visit, no?","TWN":"那可真是個好消息。至少這說明她對我的拜訪還是有點興趣的，對嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"원하신다면 제가 멱살이라도 잡아서 끌고 나올까요?","JPN":"お望みなら私が胸ぐらでも掴んで引っ張り出しましょうか？","ENG":"If you want, I could drag her out here.","TWN":"如果你想要的話，我可以幫你把前輩拖出來。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮네. 그럴 필요까진 없어.","JPN":"大丈夫だ。そこまでする必要はない。","ENG":"No, there's no need for that.","TWN":"這個……哈哈，這就不必了吧。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이졸데 양은 청사진도 없이 다이브 항법장치의 역설계를 통해 그 모방품을 만들어낼 만큼 아주 대단한 천재지.","JPN":"イゾルデ君は青写真がなくてもダイブ航法装置の逆設計を通じてその模倣品を作り上げるほどにとても優れた天才だ。","ENG":"Isolde is a genius who reverse-engineered the dive navigation device and built a replica of it without a blueprint.","TWN":"咳咳……其實，我認為伊索德是個了不起的天才，竟然能在沒有藍圖的情況下，透過逆向設計製造出躍入導航裝置的複製品。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀를 시니어로 세운 것은 그 재능을 높이 샀기 때문일세.","JPN":"彼女をシニアとして立てたのは、その才能を高く評価したからだよ。","ENG":"I appointed her as Senior because I highly valued her talent.","TWN":"我讓她成為Senior完全是因為我看重她的才能。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오늘 내가 이곳에 온 건, 자네의 그 재능이 필요해서야.","JPN":"今日私がここに来たのは、君のその才能が必要だからだ。","ENG":"And I am here today because I need your talents.","TWN":"今天我來這裡，也是因為如此。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번 부탁을 들어준다면…","JPN":"今回の頼みを聞いてくれるなら……","ENG":"If you grant me this favor...","TWN":"可惜了，如果她能答應這次的請求……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그간 비밀리에 부쳐왔던 이터니움 드라이브의 설계도를 자네에게 제공하도록 하지.","JPN":"今まで内緒にしてきたエタニウムドライブの設計図を君に提供しよう。","ENG":"I'll promise to provide you with the blueprints for the Eternium Drive that I have been keeping a secret.","TWN":"我願意把一直秘密保管的永恆之金驅動器設計圖提供出來。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};